import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { PackagePlus, ClipboardList, Store, PlusCircle, ArrowLeft, Trash2, Edit } from 'lucide-react';
import { generarNombreImagen, DICCIONARIO_PRODUCTOS, URL_CARPETA_IMAGENES } from '../utils/helpers';
import CargaMasiva from './CargaMasiva';
import VistaPedidosVendedor from './VistaPedidosVendedor';
import { useAuth } from '../context/AuthContext';

const DashboardVendedor = () => {
  const { user } = useAuth();
  const [locales, setLocales] = useState([]);
  const [localActivo, setLocalActivo] = useState(null);
  const [mostrarFormLocal, setMostrarFormLocal] = useState(false);
  const [vista, setVista] = useState('pedidos');
  const [loading, setLoading] = useState(true);

  // URL Base Fallback
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  // Estados para nuevo Local (Ajustado a tu esquema: lng, lat)
  const [nuevoLocal, setNuevoLocal] = useState({ nombre: '', direccion: '', lng: -65.2, lat: -26.8 });

  // Estados para nuevo Producto
  const [sugerencias, setSugerencias] = useState([]);
  const [form, setForm] = useState({ 
    categoria: 'Almacén', tipo: '', marca: '', contenido: '', 
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  useEffect(() => {
    if (user) fetchLocales();
  }, [user]);

  const fetchLocales = async () => {
    try {
      const userId = user.id || user._id;
      // Usamos tu ruta: /api/locales/vendedor/:vendedorId
      const res = await axios.get(`${API_URL}/api/locales/vendedor/${userId}`);
      setLocales(res.data);
    } catch (err) {
      console.error("Error al traer locales:", err);
    } finally {
      setLoading(false);
    }
  };

  const crearLocal = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`${API_URL}/api/locales`, {
        ...nuevoLocal,
        vendedorId: user.id || user._id // Tu backend usa vendedorId
      });
      setLocales([...locales, res.data]);
      setMostrarFormLocal(false);
      setNuevoLocal({ nombre: '', direccion: '', lng: -65.2, lat: -26.8 });
    } catch (err) {
      alert("Error al crear el local: " + err.response?.data?.error);
    }
  };

  const eliminarLocal = async (id, e) => {
    e.stopPropagation(); // Evita que se active el local al hacer click en borrar
    if (!window.confirm("¿Seguro que quieres eliminar este local? Se borrarán todas sus ofertas.")) return;
    try {
      await axios.delete(`${API_URL}/api/locales/${id}`);
      setLocales(locales.filter(l => l._id !== id));
    } catch (err) {
      alert("Error al eliminar");
    }
  };

  const publicarIndividual = async (e) => {
    e.preventDefault();
    const publicId = generarNombreImagen(form.tipo, form.marca, form.contenido);
    const oferta = {
      producto: `${form.tipo} ${form.marca} ${form.contenido}`,
      categoria: form.categoria,
      precioNuevo: Number(form.precioNuevo),
      precioViejo: Number(form.precioViejo || form.precioNuevo),
      stock: Number(form.stock),
      publicId: publicId,
      local: localActivo?._id,
      fechaVencimiento: form.fechaVencimiento
    };

    try {
      await axios.post(`${API_URL}/api/ofertas`, oferta);
      alert("✅ Producto publicado");
      setForm({ ...form, tipo: '', marca: '', contenido: '', precioNuevo: '', precioViejo: '', stock: '' });
    } catch (err) { alert("Error al guardar"); }
  };

  if (loading) return <div style={msgCentrado}>Cargando locales...</div>;

  // --- VISTA: LISTA DE LOCALES ---
  if (!localActivo) {
    return (
      <div style={containerStyle}>
        <div style={headerStyle}>
          <h2 style={{margin:0}}>Mis Locales</h2>
          <button onClick={() => setMostrarFormLocal(!mostrarFormLocal)} style={btnCrearLocal}>
            {mostrarFormLocal ? 'Cancelar' : <><PlusCircle size={18}/> Nuevo Local</>}
          </button>
        </div>

        {mostrarFormLocal ? (
          <form onSubmit={crearLocal} style={formStyle}>
            <h3 style={{margin:0}}>Registrar Nuevo Local</h3>
            <input style={inputStyle} placeholder="Nombre" value={nuevoLocal.nombre} onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} required />
            <input style={inputStyle} placeholder="Dirección" value={nuevoLocal.direccion} onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} required />
            <p style={{fontSize: '0.7rem', color: '#94a3b8'}}>Coordenadas (Opcional por ahora)</p>
            <div style={{display:'flex', gap:'10px'}}>
                <input style={inputStyle} type="number" step="any" placeholder="Longitud" value={nuevoLocal.lng} onChange={e => setNuevoLocal({...nuevoLocal, lng: e.target.value})} />
                <input style={inputStyle} type="number" step="any" placeholder="Latitud" value={nuevoLocal.lat} onChange={e => setNuevoLocal({...nuevoLocal, lat: e.target.value})} />
            </div>
            <button type="submit" style={btnSubmit}>Guardar Local</button>
          </form>
        ) : (
          <div style={gridLocales}>
            {locales.map(l => (
              <div key={l._id} style={cardLocal} onClick={() => setLocalActivo(l)}>
                <div style={cardActions}>
                    <button style={btnIconTrash} onClick={(e) => eliminarLocal(l._id, e)}><Trash2 size={16}/></button>
                </div>
                <Store size={40} color="#e67e22" />
                <h3 style={{margin: '10px 0 5px 0'}}>{l.nombre}</h3>
                <p style={{fontSize: '0.8rem', color: '#64748b'}}>{l.direccion}</p>
              </div>
            ))}
            {locales.length === 0 && <div style={emptyBox}>No tienes locales registrados aún.</div>}
          </div>
        )}
      </div>
    );
  }

  // --- VISTA: GESTIÓN DE LOCAL SELECCIONADO ---
  return (
    <div style={containerStyle}>
      <header style={headerStyle}>
        <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
          <button onClick={() => setLocalActivo(null)} style={btnBack}><ArrowLeft size={20}/></button>
          <div>
            <h2 style={{ margin: 0 }}>{localActivo?.nombre}</h2>
            <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>{localActivo?.direccion}</p>
          </div>
        </div>
        <div style={tabContainer}>
          <button onClick={() => setVista('pedidos')} style={vista === 'pedidos' ? tabActive : tabInactive}>
            <ClipboardList size={18} /> Pedidos
          </button>
          <button onClick={() => setVista('productos')} style={vista === 'productos' ? tabActive : tabInactive}>
            <PackagePlus size={18} /> Productos
          </button>
        </div>
      </header>

      {vista === 'pedidos' ? (
        <VistaPedidosVendedor localId={localActivo?._id} />
      ) : (
        <section>
          <CargaMasiva localId={localActivo?._id} onComplete={() => {}} />
          <form onSubmit={publicarIndividual} style={{...formStyle, marginTop: '20px'}}>
            <h3 style={formTitle}>Publicar Producto Individual</h3>
            <select style={inputStyle} value={form.categoria} onChange={e => setForm({...form, categoria: e.target.value})}>
              {Object.keys(DICCIONARIO_PRODUCTOS).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <input style={inputStyle} placeholder="Producto (ej: Leche)" value={form.tipo} onChange={e => setForm({...form, tipo: e.target.value})} required />
            <div style={{display:'flex', gap:'10px'}}>
                <input style={inputStyle} placeholder="Marca" value={form.marca} onChange={e => setForm({...form, marca: e.target.value})} required />
                <input style={inputStyle} placeholder="Contenido" value={form.contenido} onChange={e => setForm({...form, contenido: e.target.value})} required />
            </div>
            <div style={{display:'flex', gap:'10px'}}>
                <input type="number" style={inputStyle} placeholder="Precio $" value={form.precioNuevo} onChange={e => setForm({...form, precioNuevo: e.target.value})} required />
                <input type="number" style={inputStyle} placeholder="Stock" value={form.stock} onChange={e => setForm({...form, stock: e.target.value})} required />
                <input type="date" style={inputStyle} value={form.fechaVencimiento} onChange={e => setForm({...form, fechaVencimiento: e.target.value})} required />
            </div>
            <button type="submit" style={btnSubmit}>Publicar Oferta</button>
          </form>
        </section>
      )}
    </div>
  );
};

// --- ESTILOS ---
const containerStyle = { padding: '20px', maxWidth: '900px', margin: '0 auto' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', background: 'white', padding: '20px', borderRadius: '16px', border: '1px solid #e2e8f0' };
const gridLocales = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '20px' };
const cardLocal = { background: 'white', padding: '30px', borderRadius: '20px', border: '1px solid #e2e8f0', textAlign: 'center', cursor: 'pointer', position: 'relative' };
const cardActions = { position: 'absolute', top: '10px', right: '10px' };
const btnIconTrash = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '5px' };
const btnCrearLocal = { background: '#e67e22', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', gap: '8px' };
const btnBack = { background: '#f1f5f9', border: 'none', padding: '10px', borderRadius: '10px', cursor: 'pointer' };
const formStyle = { background: 'white', padding: '25px', borderRadius: '20px', border: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', gap: '15px' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none' };
const btnSubmit = { background: '#1e293b', color: 'white', padding: '14px', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' };
const tabContainer = { display: 'flex', background: '#f1f5f9', padding: '5px', borderRadius: '12px', gap: '5px' };
const tabActive = { background: 'white', padding: '8px 16px', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' };
const tabInactive = { background: 'transparent', padding: '8px 16px', border: 'none', color: '#64748b', cursor: 'pointer' };
const msgCentrado = { padding: '50px', textAlign: 'center', fontFamily: 'sans-serif' };
const emptyBox = { gridColumn: '1/-1', textAlign: 'center', padding: '40px', background: '#f1f5f9', borderRadius: '20px' };
const formTitle = { fontSize: '1.1rem', margin: '0', color: '#1e293b' };

export default DashboardVendedor;
